<template>
    <view>
        <chooseColor :color="Colors" @pickerColor="changeColors"></chooseColor>
        <view class="resultContent">
            <view class="result" :style="`background:${Colors}`"></view>
            <view class="colorList">
                <view class="colorItem" @click="selectColor(item.color)" :style="`background:${item.color}`" v-for="(item,index) in colorList">
                    <view class="colorSelected" :style="item.selected? 'border-radius:50%;border:4upx solid #fff' : '' "></view>
                </view>
            </view>
        </view>
        <view style="height: 2upx;"></view>
    </view>
</template>

<script>
    import chooseColor from "../../../../components/holy-colorPicker/colorPicker.vue"
    export default {
        components: {
            chooseColor
        },
        props:{
           source:String
        },
        data() {
            return {
                Colors: "#000000",
                colorList: [{
                        color: "#FEECD4",
                        selected: false
                    },
                    {
                        color: "#B1DD8B",
                        selected: false
                    },
                    {
                        color: "#EAF28F",
                        selected: false
                    },
                    {
                        color: "#FFC5AB ",
                        selected: false
                    },
                    {
                        color: "#B51A00",
                        selected: true
                    },
                    {
                        color: "#74A7FF",
                        selected: false
                    }, {
                        color: "#BE38F3",
                        selected: false
                    }, {
                        color: "#00A1D8",
                        selected: false
                    }, {
                        color: "#0042A9 ",
                        selected: false
                    }, {
                        color: "#787880",
                        selected: false
                    }
                ]
            }
        },
        onLoad(options) {
            console.log(options)
            // this.Colors = options.rgb
        },
        methods: {
            changeColors(e) {
                this.Colors = e.rgb
                this.colorList.forEach((value,index) => {
                    value.selected = false
                })
                let data = {}
                this.$emit("selectColor",this.Colors)
            },
            selectColor(e){
                console.log(e)
                this.Colors = e
                this.colorList.forEach((value,index) => {
                    if(value.color == e){
                        value.selected = true
                    }else{
                        value.selected = false
                    }
                })
                this.$emit("selectColor",this.Colors)
            }
        }
    }
</script>

<style lang="scss">
    .resultContent{
        display: flex;
        align-items: center;
        box-sizing: border-box;
        padding: 0 32upx;
        
        .result {
            width: 164upx;
            height: 164upx;
            border-radius: 20upx;
            flex-shrink: 0;
            margin-right: 46upx;
        }
        
        .colorList {
            display: flex;
            flex-wrap: wrap;
            padding-bottom: 40upx;
            .colorItem {
                width: 60upx;
                height: 60upx;
                border-radius: 50%;
                margin-right: 44upx;
                box-sizing: border-box;
                padding: 8upx;
                
                .colorSelected{
                    width: 100%;
                    height: 100%;
                    box-sizing: border-box;
                }
            }
            
            .colorItem:nth-child(1){
                margin-bottom: 44upx;
            }
            
            .colorItem:nth-child(5n){
                margin-right: 0;
            }
        }
    }
    
   
</style>
